import { MakeLogicType, actions, afterMount, connect, kea, listeners, path } from 'kea'

import api from 'lib/api'
import { featureFlagLogic } from 'lib/logic/featureFlagLogic'
import { teamLogic } from 'scenes/teamLogic'

import { HogQLQueryResponse, NodeKind } from '~/queries/schema/schema-general'

import type { FeatureFlagsSet } from '../../logic/featureFlagLogic'
import { productSetupStatusLogic } from './productSetupStatusLogic'
import { PRODUCT_SETUP_PROBES, statusFromProbeCounts } from './setupProbes'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface productSetupPreloadLogicValues {
    featureFlags: FeatureFlagsSet // featureFlagLogic
    currentTeamId: number | null // teamLogic
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface productSetupPreloadLogicActions {
    preloadStatuses: () => {
        value: true
    }
}

export type productSetupPreloadLogicType = MakeLogicType<
    productSetupPreloadLogicValues,
    productSetupPreloadLogicActions
>

/**
 * Resolves every registered product's setup status as early as possible — one
 * combined event-count query on idle after the team loads — and seeds
 * `productSetupStatusLogic` with the results. By the time a user first opens a
 * gated product scene, the status is usually already known, so the gate renders
 * the empty state (or the scene) directly instead of a loading spinner.
 *
 * The product's own detection logic remains the in-scene source of truth: it
 * re-checks with a fresh (uncached) query and keeps polling. The preload only
 * seeds instances still in `loading`, so it can never override a fresher answer.
 */
export const productSetupPreloadLogic = kea<productSetupPreloadLogicType>([
    path(['lib', 'components', 'ProductEmptyState', 'productSetupPreloadLogic']),
    connect(() => ({
        values: [teamLogic, ['currentTeamId'], featureFlagLogic, ['featureFlags']],
    })),
    actions({
        preloadStatuses: true,
    }),
    listeners(({ actions, values, cache }) => ({
        preloadStatuses: async (_, breakpoint) => {
            if (cache.preloaded || !values.currentTeamId) {
                return
            }
            const probes = PRODUCT_SETUP_PROBES.filter(
                (probe) => !probe.featureFlag || values.featureFlags[probe.featureFlag]
            )
            if (!probes.length) {
                return
            }
            cache.preloaded = true

            // Event names are static internal literals from the probe registry, so
            // inlining them is safe. Event-name + count on the events sort key keeps
            // this cheap even on huge projects; a cached result is fine for seeding.
            const events = [
                ...new Set(probes.flatMap((probe) => [...probe.hasDataEvents, ...(probe.waitingEvents ?? [])])),
            ]
            const query = `SELECT event, count() FROM events WHERE event IN (${events
                .map((event) => `'${event}'`)
                .join(', ')}) GROUP BY event`
            const response = (await api.query({ kind: NodeKind.HogQLQuery, query })) as HogQLQueryResponse
            breakpoint()

            const countsByEvent: Record<string, number> = {}
            for (const row of response?.results ?? []) {
                const [event, count] = row as [string, unknown]
                countsByEvent[event] = Number(count) || 0
            }

            for (const probe of probes) {
                const instance = productSetupStatusLogic.build({ productKey: probe.productKey })
                if (!instance.isMounted()) {
                    // Keep the instance alive for the app's lifetime so the seeded
                    // status is still there when the scene finally opens.
                    instance.mount()
                    cache.disposables.add(() => () => instance.unmount(), `status-${probe.productKey}`)
                }
                // Seed only unknown statuses — a product logic that already answered
                // (fresh, uncached) always beats this cached approximation.
                if (instance.values.status === 'loading') {
                    instance.actions.setDetectedStatus(statusFromProbeCounts(probe, countsByEvent))
                }
            }
        },
        // Covers login and project switches that happen after mount.
        [teamLogic.actionTypes.loadCurrentTeamSuccess]: ({ currentTeam }) => {
            if (currentTeam) {
                actions.preloadStatuses()
            }
        },
    })),
    afterMount(({ actions, cache }) => {
        // Defer to idle so boot-critical work (scene chunk, first queries) wins.
        cache.disposables.add(() => {
            const run = (): void => actions.preloadStatuses()
            if (typeof window.requestIdleCallback === 'function') {
                const id = window.requestIdleCallback(run, { timeout: 5000 })
                return () => window.cancelIdleCallback(id)
            }
            const id = window.setTimeout(run, 1000)
            return () => clearTimeout(id)
        }, 'idle-preload')
    }),
])
